#pragma once

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

// Kernel Launch Configuration
#define BLOCK_SIZE 256
#define NUM_QO_HEADS 32
#define NUM_KV_HEADS 4
#define HEAD_DIM 128
#define GQA_RATIO (NUM_QO_HEADS / NUM_KV_HEADS)

// Shared Memory Layout
// q_shared: 32 * 128 * 2 = 8192 bytes (bfloat16)
// k_shared: 4 * 128 * 2 = 1024 bytes (bfloat16)
// v_shared: 4 * 128 * 2 = 1024 bytes (bfloat16)
// acc_max: 32 * 4 = 128 bytes (float)
// acc_sum: 32 * 4 = 128 bytes (float)
// acc_out: 32 * 128 * 4 = 16384 bytes (float)
// Total: 26880 bytes (aligned to 128 bytes)
#define SHARED_MEM_SIZE 26880

// Kernel Declaration
void gqa_paged_decode_cuda(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k_cache,
    const __nv_bfloat16* v_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    __nv_bfloat16* output,
    float* lse,
    float sm_scale,
    int batch_size,
    int num_pages,
    int num_kv_indices
);

// Host Function Declaration
void run_gqa_paged_decode(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k_cache,
    const __nv_bfloat16* v_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    __nv_bfloat16* output,
    float* lse,
    float sm_scale,
    int batch_size,
    int num_pages,
    int num_kv_indices
);

#include "kernel.h"
#include <math_constants.h>
#include <cstdio>

__global__ void gqa_paged_decode_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    float sm_scale,
    int batch_size
) {
    int b = blockIdx.x;
    if (b >= batch_size) return;

    int tid = threadIdx.x;

    // Shared Memory Layout with proper offsets
    extern __shared__ unsigned char smem[];

    // Calculate shared memory offsets
    size_t q_offset = 0;
    size_t k_offset = NUM_QO_HEADS * HEAD_DIM * 2;
    size_t v_offset = k_offset + NUM_KV_HEADS * HEAD_DIM * 2;
    size_t acc_max_offset = v_offset + NUM_KV_HEADS * HEAD_DIM * 2;
    size_t acc_sum_offset = acc_max_offset + NUM_QO_HEADS * 4;
    size_t acc_out_offset = acc_sum_offset + NUM_QO_HEADS * 4;

    __nv_bfloat16* q_shared = reinterpret_cast<__nv_bfloat16*>(smem + q_offset);
    __nv_bfloat16* k_shared = reinterpret_cast<__nv_bfloat16*>(smem + k_offset);
    __nv_bfloat16* v_shared = reinterpret_cast<__nv_bfloat16*>(smem + v_offset);
    float* acc_max = reinterpret_cast<float*>(smem + acc_max_offset);
    float* acc_sum = reinterpret_cast<float*>(smem + acc_sum_offset);
    float* acc_out = reinterpret_cast<float*>(smem + acc_out_offset);

    // Sequence Info
    int seq_start = kv_indptr[b];
    int seq_end = kv_indptr[b + 1];
    int seq_len = seq_end - seq_start;

    // Initialize Accumulators
    if (tid < NUM_QO_HEADS) {
        acc_max[tid] = -INFINITY;
        acc_sum[tid] = 0.0f;
    }
    if (tid < NUM_QO_HEADS * HEAD_DIM) {
        acc_out[tid] = 0.0f;
    }

    __syncthreads();

    // Load Q into Shared Memory
    // Each thread loads one element of Q (bfloat16 = 2 bytes)
    if (tid < NUM_QO_HEADS * HEAD_DIM) {
        int q_idx = b * NUM_QO_HEADS * HEAD_DIM + tid;
        q_shared[tid] = q[q_idx];
    }
    __syncthreads();

    // Loop over sequence tokens
    for (int t = 0; t < seq_len; t++) {
        int page_id = kv_indices[seq_start + t];

        // Load K and V into Shared Memory
        // Each thread loads one KV head element
        if (tid < NUM_KV_HEADS * HEAD_DIM) {
            int kv_head = tid / HEAD_DIM;
            int dim = tid % HEAD_DIM;
            int k_idx = page_id * NUM_KV_HEADS * HEAD_DIM + kv_head * HEAD_DIM + dim;
            int v_idx = k_idx;
            k_shared[tid] = k_cache[k_idx];
            v_shared[tid] = v_cache[v_idx];
        }
        __syncthreads();

        // Compute Attention for each Q head
        // Each thread handles one Q head
        if (tid < NUM_QO_HEADS) {
            int q_head = tid;
            int kv_head_idx = q_head / GQA_RATIO; // GQA mapping

            // Compute Dot Product Q . K
            float partial_logit = 0.0f;
            for (int d = 0; d < HEAD_DIM; d++) {
                float q_val = __bfloat162float(q_shared[q_head * HEAD_DIM + d]);
                float k_val = __bfloat162float(k_shared[kv_head_idx * HEAD_DIM + d]);
                partial_logit += q_val * k_val;
            }

            float scaled_logit = partial_logit * sm_scale;

            // Online softmax update
            float old_max = acc_max[q_head];
            float new_max_val = fmaxf(old_max, scaled_logit);

            // Update max
            acc_max[q_head] = new_max_val;

            // Handle -INFINITY case to avoid NaN in expf(-INFINITY - (-INFINITY))
            float scale_factor;
            if (old_max == -INFINITY) {
                scale_factor = 0.0f;
            } else {
                scale_factor = expf(old_max - new_max_val);
            }

            // Update acc_sum
            float old_sum = acc_sum[q_head];
            float exp_new;
            if (scaled_logit == -INFINITY) {
                exp_new = 0.0f;
            } else {
                exp_new = expf(scaled_logit - new_max_val);
            }
            acc_sum[q_head] = old_sum * scale_factor + exp_new;

            // Update acc_out
            for (int d = 0; d < HEAD_DIM; d++) {
                float v_val = __bfloat162float(v_shared[kv_head_idx * HEAD_DIM + d]);
                float old_out = acc_out[q_head * HEAD_DIM + d];
                acc_out[q_head * HEAD_DIM + d] = old_out * scale_factor + exp_new * v_val;
            }
        }
        __syncthreads();
    }

    // Finalize Output and LSE
    if (tid < NUM_QO_HEADS) {
        int q_head = tid;
        float final_max = acc_max[q_head];
        float final_sum = acc_sum[q_head];

        // Compute 2-base LSE: log2(sum(exp(logits)))
        // = (ln(sum(exp(logits)))) / ln(2)
        // = (final_max + ln(final_sum)) / ln(2)
        float lse_val;
        if (final_sum <= 0.0f || !isfinite(final_sum) || !isfinite(final_max)) {
            lse_val = -INFINITY;
        } else {
            lse_val = (final_max + logf(final_sum)) / 0.69314718056f;
        }
        lse[b * NUM_QO_HEADS + q_head] = lse_val;

        // Normalize output
        float scale;
        if (final_sum <= 0.0f || !isfinite(final_sum)) {
            scale = 0.0f;
        } else {
            scale = 1.0f / final_sum;
        }
        for (int d = 0; d < HEAD_DIM; d++) {
            float out_val = acc_out[q_head * HEAD_DIM + d] * scale;
            output[b * NUM_QO_HEADS * HEAD_DIM + q_head * HEAD_DIM + d] = __float2bfloat16(out_val);
        }
    }
}

void run_gqa_paged_decode(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k_cache,
    const __nv_bfloat16* v_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    __nv_bfloat16* output,
    float* lse,
    float sm_scale,
    int batch_size,
    int num_pages,
    int num_kv_indices
) {
    if (batch_size == 0) return;

    // Shared Memory Size Calculation
    size_t smem_size = SHARED_MEM_SIZE;

    dim3 grid(batch_size);
    dim3 block(BLOCK_SIZE);

    gqa_paged_decode_kernel<<<grid, block, smem_size>>>(
        q, k_cache, v_cache, kv_indptr, kv_indices, output, lse, sm_scale, batch_size
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include "kernel.h"
#include <stdexcept>
#include <vector>
#include <cuda_bf16.h>

void run_gqa_paged_decode_host(
    const at::Tensor& q,
    const at::Tensor& k_cache,
    const at::Tensor& v_cache,
    const at::Tensor& kv_indptr,
    const at::Tensor& kv_indices,
    at::Tensor& output,
    at::Tensor& lse,
    float sm_scale
) {
    // Validate inputs
    TORCH_CHECK(q.is_cuda(), "q must be a CUDA tensor");
    TORCH_CHECK(k_cache.is_cuda(), "k_cache must be a CUDA tensor");
    TORCH_CHECK(v_cache.is_cuda(), "v_cache must be a CUDA tensor");
    TORCH_CHECK(kv_indptr.is_cuda(), "kv_indptr must be a CUDA tensor");
    TORCH_CHECK(kv_indices.is_cuda(), "kv_indices must be a CUDA tensor");
    TORCH_CHECK(output.is_cuda(), "output must be a CUDA tensor");
    TORCH_CHECK(lse.is_cuda(), "lse must be a CUDA tensor");

    TORCH_CHECK(q.scalar_type() == at::ScalarType::BFloat16, "q must be bfloat16");
    TORCH_CHECK(k_cache.scalar_type() == at::ScalarType::BFloat16, "k_cache must be bfloat16");
    TORCH_CHECK(v_cache.scalar_type() == at::ScalarType::BFloat16, "v_cache must be bfloat16");
    TORCH_CHECK(kv_indptr.scalar_type() == at::ScalarType::Int, "kv_indptr must be int32");
    TORCH_CHECK(kv_indices.scalar_type() == at::ScalarType::Int, "kv_indices must be int32");
    TORCH_CHECK(output.scalar_type() == at::ScalarType::BFloat16, "output must be bfloat16");
    TORCH_CHECK(lse.scalar_type() == at::ScalarType::Float, "lse must be float32");

    int batch_size = q.size(0);
    int num_qo_heads = q.size(1);
    int head_dim = q.size(2);
    int num_pages = k_cache.size(0);
    int num_kv_indices = kv_indices.size(0);

    // Validate Constants
    TORCH_CHECK(num_qo_heads == 32, "num_qo_heads must be 32");
    TORCH_CHECK(head_dim == 128, "head_dim must be 128");
    TORCH_CHECK(k_cache.size(2) == 4, "num_kv_heads must be 4");
    TORCH_CHECK(kv_indptr.size(0) == batch_size + 1, "len_indptr must be batch_size + 1");
    TORCH_CHECK(kv_indices.size(0) == kv_indptr[batch_size].item<int>(), "num_kv_indices must match kv_indptr[-1]");

    // Extract pointers using data_ptr with explicit template
    const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr());
    const __nv_bfloat16* k_cache_ptr = reinterpret_cast<const __nv_bfloat16*>(k_cache.data_ptr());
    const __nv_bfloat16* v_cache_ptr = reinterpret_cast<const __nv_bfloat16*>(v_cache.data_ptr());
    const int32_t* kv_indptr_ptr = kv_indptr.data_ptr<int32_t>();
    const int32_t* kv_indices_ptr = kv_indices.data_ptr<int32_t>();
    __nv_bfloat16* output_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr());
    float* lse_ptr = lse.data_ptr<float>();

    // Launch Kernel
    run_gqa_paged_decode(
        q_ptr,
        k_cache_ptr,
        v_cache_ptr,
        kv_indptr_ptr,
        kv_indices_ptr,
        output_ptr,
        lse_ptr,
        sm_scale,
        batch_size,
        num_pages,
        num_kv_indices
    );

    cudaDeviceSynchronize();
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale,
    torch::Tensor output,
    torch::Tensor lse
) {
    run_gqa_paged_decode_host(q, k_cache, v_cache, kv_indptr, kv_indices, output, lse, sm_scale);

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GQA Paged Decode Kernel");
}
